class Solution(object):
    def destroyTargets(self, nums, space):
        from collections import defaultdict
        count = defaultdict(int)
        for num in nums:
            count[num % space] += 1
        max_count = max(count.values())
        min_seed = float('inf')
        for num in nums:
            if count[num % space] == max_count:
                min_seed = min(min_seed, num)
        return min_seed
